import React from "react";
import Header from "./header";
import { Link, withRouter} from "react-router-dom";
import {getActiveFilters,insertActiveFilters} from "../helpers";
import { debounce } from "lodash";
import { withApollo } from "react-apollo";
import AppCategoriesDropdown from "./appCategoriesDropdown";
import StoryCategoriesDropdown from "./storyCategoriesDropdown";
import StoryElementsDropdown from "./storyElementsDropdown";
import StoryCategoriesActiveFitlers from "./storyCategoriesActiveFitlers";
import StoryElementsActiveFilters from "./storyElementsActiveFilters";
import { compose } from "recompose";
import { storiesIndexHelper } from "../algoliaClients";
import { if_user_call_func, onAlgoliaError } from "../helpers";
import PickMembershipModal from "./pickMembershipModal"; 
import DropdownWrapper from "./wrappers/dropdownWrapper";
import StoryItem from "./storyItem";

const SKELETON = <div>
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
  <img style={{ borderRadius: 30, width: 250, height: 550, marginRight: 25, marginBottom: 10 }} src="data:image/png;base64," />
</div>

class _Stories extends React.Component {
  constructor(props){
    super(props);
    let filterBy = {
      appCategory: "all",
      storyCategories: {},
      storyElements: {}
    }
    if (this.props.location && this.props.location.state && this.props.location.state.filterBy){
      filterBy = this.props.location.state.filterBy
      storiesIndexHelper.state.facetsRefinements = {}
      if (filterBy.appCategory && filterBy.appCategory !== "all"){
        storiesIndexHelper.toggleFacetRefinement("app.appCategory.name",filterBy.appCategory)
      }
      for (var key in filterBy.storyElements){
        if (filterBy.storyElements[key]){
          storiesIndexHelper.toggleFacetRefinement("storyElements.name", key)
        }
      } 
      for (var key in filterBy.storyCategories) {
        if (filterBy.storyCategories[key]) {
          storiesIndexHelper.toggleFacetRefinement("storyCategories.name", key)
        }
      } 

    }
    this.state = {
      stories: undefined,
      appCategories: undefined,
      storyCategories: undefined,
      storyElements: undefined,
      filterBy: filterBy,
      reached_end: false
    }
    this.search = debounce( this.search.bind(this), 150 );
    this.resetFilters = this.resetFilters.bind(this);
    this.toggle = this.toggle.bind(this);
    this.once = false
    this.searchNode = undefined
    this.hitsPerPage = 8
    this.appCategoriesToggleButton = React.createRef()
    this.storyCategoriesToggleButton = React.createRef()
    this.storyElementsToggleButton = React.createRef()
    this.setState = this.setState.bind(this)
  }
  componentWillUnmount(){
    storiesIndexHelper.setQuery("");
    storiesIndexHelper.clearRefinements()
  }
  hasActiveFitlers(){
    return (this.state.filterBy.appCategory && !(this.state.filterBy.appCategory === "all")) || 
          (this.state.filterBy.storyCategories && this.state.filterBy.storyCategories.length) ||
          (this.state.filterBy.storyElements && this.state.filterBy.storyElements.length)
  }
  async componentDidMount() {
    this.search("",true);
  }
  async search(storyName_contains,firstTime,pagination=false) {
    this.setState(prevState => {
      let state = prevState
      if (!pagination) state.stories = undefined
      state.pagination_skeleton = pagination
      return state;
    })
    let filters = {"storyCategories":[],"storyElements":[]};
    filters = insertActiveFilters(filters,this.state);
    if (pagination){
      storiesIndexHelper.state.hitsPerPage += this.hitsPerPage
    }
    
    storiesIndexHelper.setQuery(storyName_contains).search();
    onAlgoliaError(storiesIndexHelper, this.setState, { pagination_skeleton: false })
    storiesIndexHelper.on("result",data => {
      var results = { data: { stories: data.hits }}
      let stories = results.data.stories;
      this.setState(prevState => {
        let state = prevState;
        state.reached_end = stories.length < storiesIndexHelper.state.hitsPerPage
        if (pagination){
          let new_stories = stories.slice(state.stories.length, 999)
          state.stories = state.stories.concat(new_stories);
        } else {
          state.stories = stories
        }
        state.pagination_skeleton =  false
        return state
      })
    })
  }
  componentWillMount(){
    // storiesIndexHelper.state.hitsPerPage = this.hitsPerPage
  }
  async handleFilterClick(e,obj,type) {
    storiesIndexHelper.state.hitsPerPage = this.hitsPerPage
    if (type === "appCategory") {
      storiesIndexHelper.state.facetsRefinements["app.appCategory.name"] = []
      if (obj.name !== "all") {
        storiesIndexHelper.toggleFacetRefinement("app.appCategory.name", obj.name);
      }
    } else {
      storiesIndexHelper.toggleFacetRefinement(`${type}.name`, obj.name);
    }
    this.setState((prevState) => {
      let state = prevState;
      // state.stories = undefined;
      if (type === "appCategory") {
        state.filterBy.appCategory = obj.name
      } else {
        state.filterBy[type] = {
          ...state.filterBy[type],
          [obj.name] : !state.filterBy[type][obj.name]
        }
      }
      return state
    })
    this.search(this.searchNode.value)
  }
  resetFilters(){
    this.setState(prevState => {
      let state = prevState;
      state.filterBy.appCategory = undefined
      state.filterBy.storyCategories = {}
      state.filterBy.storyElements = {}
      state.pagination_skeleton = true
      state.stories = undefined
      storiesIndexHelper.state.facetsRefinements = {}
      return state;
    },() => this.search(this.searchNode.value))
  }
  unFilter(type,obj){
    if (this.state.stories){
      this.setState({
        stories: undefined
      })
    }
    this.setState(prevState => {
      let state = prevState;
      if (type === "appCategory"){
        storiesIndexHelper.state.facetsRefinements["app.appCategory.name"] = []
        state.filterBy.appCategory = undefined
      } else {
        let facets = storiesIndexHelper.state.facetsRefinements[`${type}.name`];
        let obj_name = obj
        storiesIndexHelper.state.facetsRefinements[`${type}.name`] = facets.filter(x => x !== obj_name);
        state.filterBy[type][obj] = false;
      }
      return state;
      },() => this.search(this.searchNode.value))
    }
  toggle(name) {
    this.setState(nextState => {
      nextState.currentDropdown = nextState.currentDropdown === name ? undefined : name
      return nextState;
    })
  }
  render() {
    return (
      <div>
      <Header 
        user={this.props.user}
        opened={this.state.currentDropdown === "profileDropdown"}
        toggleOpened={() => this.toggle("profileDropdown")}
        closeDropdown={() => this.setState({currentDropdown: undefined})}
      />
        <PickMembershipModal
          modalIsOpen={this.state.currentModal === "PickMembershipModal"}
          closeModal={(e) => this.setState({ currentModal: undefined })}
        />
        <div>
          <div className="secondary-header">
            <div className="container">
              <div className="secodary-header__content">
                <div className="flex  ac">
                  <h2 className="white">Browse Stories</h2>
                  <span className="seperator" />
                  <div className="search">
                    <img src="/assets/toolkit/images/search-icon.svg" alt />
                    <input ref={node => this.searchNode = node} onChange={(e) => {
                      this.setState({
                        stories: undefined,
                        pagination_skeleton: true
                      })  
                      this.search(e.target.value)
                    }} type="text" placeholder="Search by story..." />
                  </div>      </div>
                <div className="flex">
        <button ref={this.appCategoriesToggleButton} onClick={e => this.toggle("appCategoriesFilterOpen")} className="button white fbtn" aria-controls="first" data-is-focus="false" data-yeti-box="first" aria-haspopup="true" aria-expanded="false">Filter with Categories<img src="/assets/toolkit/images/shape.svg" alt /></button>        
        <DropdownWrapper
          toggleButton={this.appCategoriesToggleButton}
          toggleDropdown={() => this.toggle("appCategoriesFilterOpen")}
          displayed={this.state.currentDropdown === "appCategoriesFilterOpen"}
        >
          <AppCategoriesDropdown 
            filterBy={this.state.filterBy}
            open={this.state.currentDropdown === "appCategoriesFilterOpen"}
            style={{ top: "44px", left: "-198.25px" }}
            handleAllFilterClick={e => this.handleFilterClick(e,{id:"all",name:"all"},"appCategory")}
            handleFilterClick={(e,appCategory) => this.handleFilterClick(e,appCategory,"appCategory")}
            use_name={true} 
          />
        </DropdownWrapper>

        <button ref={this.storyCategoriesToggleButton} onClick={e => this.toggle("storyCategoriesFilterOpen")} className="button white fbtn">Filter with Stories<img src="../../assets/toolkit/images/shape.svg" alt /></button>
        <DropdownWrapper
          toggleButton={this.storyCategoriesToggleButton}
          toggleDropdown={() => this.toggle("storyCategoriesFilterOpen")}
          displayed={this.state.currentDropdown === "storyCategoriesFilterOpen"}
        >
          <StoryCategoriesDropdown 
            filterBy={this.state.filterBy}
            state={this.state}
            style={{ top: "43.8984px", left: "-173.367px" }}
            open={this.state.currentDropdown === "storyCategoriesFilterOpen"}
            handleFilterClick={(e,storyCategory) => this.handleFilterClick(e,storyCategory,"storyCategories")}
            use_name={true}
          />
        </DropdownWrapper>

        <button ref={this.storyElementsToggleButton} onClick={e => this.toggle("storyElementsFilterOpen")} className="button white fbtn">Filter with Elements<img src="../../assets/toolkit/images/shape.svg" alt /></button>
        <DropdownWrapper
          toggleButton={this.storyElementsToggleButton}
          toggleDropdown={() => this.toggle("storyElementsFilterOpen")}
          displayed={this.state.currentDropdown === "storyElementsFilterOpen"}
        >
          <StoryElementsDropdown
            filterBy={this.state.filterBy}
            open={this.state.currentDropdown === "storyElementsFilterOpen"}
            style={{ top: "43.8984px", left: "-188.641px" }}
            state={this.state}
            handleFilterClick={(e,storyElement) => this.handleFilterClick(e,storyElement,"storyElements")}
            use_name={true}
          />
        </DropdownWrapper>

                </div>
              </div>
            </div>
          </div>
            <div>
          <div>
        </div>
          <div className="results">
            <div className="container">
              <div className="results__content">
              {
                !this.hasActiveFitlers() ? null
                : <p style={{fontWeight:"bold"}} className="results__results bold">Showing {this.state.stories ? this.state.stories.length : 0} Results</p>
              }
                {
                  this.state.filterBy.appCategory && this.state.filterBy.appCategory !== "all" ? 
                  (
                        <div className="ux-label ">
                          <p className="light-gray">{this.state.filterBy.appCategory}</p>
                          <span><a href="#"><img onClick={() => this.unFilter("appCategory")} src="/assets/toolkit/images/008-delete.svg" alt /></a></span>
                        </div>  
                  )
                  :
                  (
                    ""
                  )
                }
                  <StoryCategoriesActiveFitlers 
                    state={this.state}
                    unFilter={(e,storyCategory) => this.unFilter("storyCategories",storyCategory)}
                    is_name={true}
                  />
                  <StoryElementsActiveFilters 
                    state={this.state}
                    unFilter={(e,storyElement) => this.unFilter("storyElements",storyElement)}
                    is_name={true}
                  />
              {
                !((this.state.filterBy.appCategory && this.state.filterBy.appCategory !== "all") || getActiveFilters(this.state,"storyElements").concat(getActiveFilters(this.state,"storyCategories")).length) ?  "" :
                  <p onClick={this.resetFilters} className="pink"><a href="#">Clear all filters</a></p>
              }
              </div>
            </div>
          </div>
                {
                      this.state.stories && !this.state.stories.length ? <h6 style={{paddingLeft:"26%"}}>Nothing to show, try different filters or query.</h6> : ""
                }
            <div className="cards">
            <center>
              <div className="container">
                <div className="cards__content">
                {
                  this.state.stories === undefined ? SKELETON
                  :
                  
                  (
                    this.state.stories.map((story,i) => 
                      <StoryItem
                        state={{
                            from_story: true,
                            filterBy: this.state.filterBy,
                            stories: this.state.stories,
                            index: i
                          }}
                          story={story}
                          style={{borderRadius:30,width:250,height:550,marginRight:25,marginBottom:10}}
                        />
                    )
                  )
                }
                {
                      this.state.pagination_skeleton ? SKELETON : null
                } 
                </div>
              </div>
              {
                  this.state.reached_end 
                  ? <h3></h3>
                  : <h3 onClick={() => if_user_call_func(
                      this.props.user,
                      () => this.search(this.searchNode.value,false,true)
                      ,this.setState.bind(this))}
                    >Load more</h3>
              }
            </center>
          </div>
        </div>
      </div>
      </div>
    );
  }
};

export default compose(withApollo,withRouter)(_Stories);