import React from "react";

class StoryThumbnailLoading extends React.Component {
	render(){
		return (
			<a href="#">
				<img 
					src="data:image/png;base64," 
					style={{ height: 450,width: 230, borderRadius: '25px' }}
				/>
			</a>
		);
	}
}

export default StoryThumbnailLoading;